// Merge RSS metadata with extracted article text
const rssData = $('Fetch Full Article').first().json;
const htmlData = $input.first().json;

const articleText = htmlData.article_text || '';

// Skip if article text is too short (paywall / extraction failed)
if (articleText.length < 300) {
  console.log('Skipping: Article too short, likely paywalled or extraction failed');
  return [];
}

return [{
  json: {
    link: rssData.link || '',
    title: rssData.title || 'Unknown Title',
    pubDate: rssData.pubDate || '',
    article_text: articleText.substring(0, 12000) // Trim to 12k chars to stay within token limits
  }
}];

