// Parse Gemini response and filter non-security articles
try {
  const rawText = $input.first().json.candidates[0].content.parts[0].text;
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const data = JSON.parse(cleaned);

  if (data.skip) {
    console.log('Skipping non-security article');
    return [];
  }

  // Attach the original article text for Groq to use
  const prepData = $('Prepare & Validate Data').first().json;
  data.article_text = prepData.article_text;
  data.source_link = prepData.link;
  data.pub_date = prepData.pubDate;

  return [{ json: data }];
} catch(e) {
  console.log('Gemini parse error:', e.message);
  return [];
}

