// Parse Groq response and merge with Gemini classification
try {
  const groqRaw = $input.first().json.choices[0].message.content;
  const groqCleaned = groqRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const groqData = JSON.parse(groqCleaned);

  const geminiData = $('Parse Gemini + Filter').first().json;

  const fullContent = [
    `## 🔍 Root Cause Analysis\n${groqData.root_cause_analysis}`,
    `## 🎯 Exploitation Walkthrough\n${groqData.exploitation_walkthrough}`,
    `## 💣 Payloads & Commands\n${groqData.payloads_and_commands}`,
    `## 💥 Impact Assessment\n${groqData.impact_assessment}`,
    `## 🔗 Chaining Opportunities\n${groqData.chaining_opportunities}`,
    `## 🔎 Detection Tips\n${groqData.detection_tips}`,
    `## 🛡️ Remediation\n${groqData.remediation}`,
    `## ⚡ Key Takeaways\n${groqData.key_takeaways}`
  ].join('\n\n');

  return [{
    json: {
      // Notion database properties
      title: geminiData.title,
      category: geminiData.category,
      vulnerability_type: geminiData.vulnerability_type,
      severity: geminiData.severity,
      tools_used: Array.isArray(geminiData.tools_mentioned) ? geminiData.tools_mentioned : [],
      source_url: geminiData.source_link,
      root_cause: groqData.root_cause_analysis ? groqData.root_cause_analysis.substring(0, 2000) : '',
      exploitation_method: groqData.exploitation_walkthrough ? groqData.exploitation_walkthrough.substring(0, 2000) : '',
      impact: groqData.impact_assessment ? groqData.impact_assessment.substring(0, 1000) : '',
      chaining_potential: groqData.chaining_opportunities ? groqData.chaining_opportunities.substring(0, 1000) : '',
      key_takeaways: groqData.key_takeaways ? groqData.key_takeaways.substring(0, 1000) : '',
      // Full body content for Notion page
      full_content: fullContent
    }
  }];
} catch(e) {
  console.log('Groq parse error:', e.message);
  return [];
}

